// ─── Spending Categories ───────────────────────────────────────
const CATEGORIES = [
  { id: 'food',          label: 'Food & Dining',  color: '#f59e0b', icon: '🍔' },
  { id: 'transport',     label: 'Transport',       color: '#3b82f6', icon: '🚗' },
  { id: 'shopping',      label: 'Shopping',        color: '#a855f7', icon: '🛍️' },
  { id: 'entertainment', label: 'Entertainment',   color: '#ec4899', icon: '🎬' },
  { id: 'health',        label: 'Health',          color: '#06d6a0', icon: '💊' },
  { id: 'utilities',     label: 'Utilities',       color: '#64748b', icon: '⚡' },
  { id: 'income',        label: 'Income',          color: '#22c55e', icon: '💰' },
];

export default CATEGORIES;
